INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  'f467e6e3-d0c6-489a-8a8f-bc75104f6a7d', 'male_sexual_health', 1,
  'Reset & Activation', 'Day 1 - Reset & Activation', '', 12,
  '[{"type":"intro","dayNumber":1,"dayTitle":"Reset & Activation","goal":"Begin breaking automatic habits, calm the mind when urges appear, and activate the muscles that\nsupport blood flow and sexual strength.","estimatedMinutes":12},{"type":"lesson","title":"Why today matters","paragraphs":["Begin breaking automatic habits, calm the mind when urges appear, and activate the muscles that","support blood flow and sexual strength."],"highlight":"Begin breaking automatic habits, calm the mind when urges appear, and activate the muscles that"},{"type":"calm_trigger","context":"If the urge to watch porn appears, tap the CALM option in the app."},{"type":"breathing_exercise","title":"Performance Anxiety Reset","pattern":{"inhaleSeconds":4,"holdSeconds":2,"exhaleSeconds":6},"cycles":10,"instructions":"Keep the shoulders soft and let the exhale do most of the calming work."},{"type":"exercise_routine","title":"15 Minute Vitality Exercise","totalDuration":"15 minutes","exercises":[{"name":"Pelvic Strength - Kegels","instructions":["This exercise strengthens the pelvic floor muscles, which support erection strength and control.","How to perform:","Tighten the muscle you would use to stop urination mid-flow","Hold the contraction for 5 seconds","Relax the muscle for 5 seconds","That equals 1 repetition.","10 reps × 3 sets","Keep your:","stomach relaxed","thighs relaxed","breathing normal"],"rest":"10–15 seconds"},{"name":"Pelvic Blood Flow - Glute Bridges","instructions":["Lie on your back with knees bent","Feet flat on the floor","Arms resting beside your body","Push through your heels","Lift your hips upward","Squeeze the glutes","Hold 3 seconds","Lower slowly","12 reps × 3 sets"],"rest":"20 seconds"},{"name":"Hormone Activation - Bodyweight Squats","instructions":["Stand with feet shoulder-width apart","Keep chest upright","Lower hips like sitting on a chair","Push through your heels to stand up","15 reps × 3 sets"],"rest":"20 seconds"},{"name":"Circulation Boost - Brisk Walk / Light Jog","instructions":["Take a 20 minute brisk walk or light jog.","Improve cardiovascular health","Increase blood circulation","Reduce stress hormones"],"duration":"20 minute brisk walk"}]},{"type":"action_step","stepNumber":4,"title":"Night Routine","duration":"30 minutes","instructions":["Before sleep tonight:","Avoid phone usage 30 minutes before bed.","Instead:","stretch lightly breathe slowly allow your body to relax Quality sleep supports hormones and recovery."],"whyThisWorks":"Better sleep supports hormone balance, recovery, and calmer nervous-system function."},{"type":"close","message":"Day 1 is complete.","secondaryMessage":"Begin breaking automatic habits, calm the mind when urges appear, and activate the muscles that\nsupport blood flow and sexual strength."}]'::jsonb
)
