INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  'f467e6e3-d0c6-489a-8a8f-bc75104f6a7d', 'male_sexual_health', 3,
  'Breaking the Habit Loop', 'Day 3 - Breaking the Habit Loop', '', 12,
  '[{"type":"intro","dayNumber":3,"dayTitle":"Breaking the Habit Loop","goal":"Start interrupting the automatic habit cycle, strengthen mental control over urges, and continue\nimproving blood flow and pelvic strength.","estimatedMinutes":12},{"type":"lesson","title":"Why today matters","paragraphs":["Start interrupting the automatic habit cycle, strengthen mental control over urges, and continue","improving blood flow and pelvic strength."],"highlight":"Start interrupting the automatic habit cycle, strengthen mental control over urges, and continue"},{"type":"calm_trigger","context":"If the urge to watch porn appears, tap the CALM option in the app."},{"type":"action_step","stepNumber":2,"title":"Habit Interrupt Technique","duration":"1 minute","instructions":["Today practice this rule:","When an urge appears:","Stand up immediately Take 10 deep breaths Walk around for 1 minute Changing your physical state interrupts the automatic habit loop."],"whyThisWorks":"Interrupting the routine weakens the automatic link between trigger and response."},{"type":"breathing_exercise","title":"Performance Anxiety Reset","pattern":{"inhaleSeconds":4,"holdSeconds":2,"exhaleSeconds":6},"cycles":10,"instructions":"Keep the shoulders soft and let the exhale do most of the calming work."},{"type":"exercise_routine","title":"15 Minute Vitality Exercise","totalDuration":"15 minutes","exercises":[{"name":"Pelvic Strength - Kegels","instructions":["Tighten the muscle used to stop urination mid-flow.","Steps:","Contract the pelvic floor muscle","Hold for 5 seconds","Relax for 5 seconds","10 reps × 3 sets","Keep your breathing relaxed."],"rest":"10–15 seconds"},{"name":"Pelvic Blood Flow - Glute Bridges","instructions":["Lie on your back with knees bent","Feet flat on the floor","Arms beside your body","Push through your heels","Lift hips upward","Squeeze glutes","Hold 3 seconds","Lower slowly","12 reps × 3 sets"],"rest":"20 seconds"},{"name":"Hormone Activation - Bodyweight Squats","instructions":["Stand with feet shoulder-width apart","Lower hips like sitting on a chair","Keep chest upright","Push through heels to stand up","15 reps × 3 sets"],"rest":"20 seconds"},{"name":"Circulation Boost - Brisk Walk / Light Jog","instructions":["Take a 20 minute brisk walk or light jog.","Improve cardiovascular health","Increase blood circulation","Reduce stress hormones"],"duration":"20 minute brisk walk"}]},{"type":"action_step","stepNumber":5,"title":"Night Routine","duration":"30 minutes","instructions":["Before sleep tonight:","Avoid phone usage 30 minutes before bed.","Instead:","stretch lightly take slow breaths allow your body to relax Better sleep supports recovery and hormone balance."],"whyThisWorks":"Better sleep supports hormone balance, recovery, and calmer nervous-system function."},{"type":"close","message":"Day 3 is complete.","secondaryMessage":"Start interrupting the automatic habit cycle, strengthen mental control over urges, and continue\nimproving blood flow and pelvic strength."}]'::jsonb
)
