  '[{"type":"intro","dayNumber":4,"dayTitle":"Dopamine Reset","goal":"Reduce overstimulation, strengthen self-control over urges, and continue building physical strength\nthat supports sexual health.","estimatedMinutes":12},{"type":"lesson","title":"Why today matters","paragraphs":["Reduce overstimulation, strengthen self-control over urges, and continue building physical strength","that supports sexual health."],"highlight":"Reduce overstimulation, strengthen self-control over urges, and continue building physical strength"},{"type":"calm_trigger","context":"If the urge to watch porn appears, tap the CALM option in the app."},{"type":"action_step","stepNumber":2,"title":"Dopamine Reset Rule","duration":"1 minute","instructions":["Today follow this simple rule:","When you feel bored or restless, avoid immediately opening social media or adult content.","Instead try one of these:","Take a 1 minute walk Drink a glass of water Stretch your body Take 10 slow breaths This helps your brain reduce overstimulation and regain balance."],"whyThisWorks":"Interrupting the routine weakens the automatic link between trigger and response."},{"type":"breathing_exercise","title":"Performance Anxiety Reset","pattern":{"inhaleSeconds":4,"holdSeconds":2,"exhaleSeconds":6},"cycles":10,"instructions":"Keep the shoulders soft and let the exhale do most of the calming work."},{"type":"exercise_routine","title":"15 Minute Vitality Exercise","totalDuration":"15 minutes","exercises":[{"name":"Pelvic Strength - Kegels","instructions":["Tighten the muscle used to stop urination mid-flow.","Steps:","Contract the pelvic floor muscle","Hold for 5 seconds","Relax for 5 seconds","10 reps × 3 sets","Keep breathing normally."],"rest":"10–15 seconds"},{"name":"Pelvic Blood Flow - Glute Bridges","instructions":["Lie on your back with knees bent","Feet flat on the floor","Arms beside your body","Push through your heels","Lift hips upward","Squeeze glutes","Hold 3 seconds","Lower slowly","12 reps × 3 sets"],"rest":"20 seconds"},{"name":"Hormone Activation - Bodyweight Squats","instructions":["Stand with feet shoulder-width apart","Lower hips like sitting on a chair","Keep chest upright","Push through heels to stand up","15 reps × 3 sets"],"rest":"20 seconds"},{"name":"Circulation Boost - Brisk Walk / Light Jog","instructions":["Take a 20 minute brisk walk or light jog.","Improve cardiovascular health","Increase blood circulation","Reduce stress hormones"],"duration":"20 minute brisk walk"}]},{"type":"action_step","stepNumber":5,"title":"Night Routine","duration":"30 minutes","instructions":["Before sleep tonight:","Avoid phone usage 30 minutes before bed.","Instead:","stretch lightly breathe slowly relax the body Quality sleep helps support recovery and hormone balance"],"whyThisWorks":"Better sleep supports hormone balance, recovery, and calmer nervous-system function."},{"type":"close","message":"Day 4 is complete.","secondaryMessage":"Reduce overstimulation, strengthen self-control over urges, and continue building physical strength\nthat supports sexual health."}]'::jsonb
